+export const normalizeComponentName = (name: string) => {
+  let parts = name.split("-")
+
+  while (
+    parts.length > 1 &&
+    ["basic", "explorer"].includes(parts[parts.length - 1])
+  ) {
+    parts.pop()
+  }
+
+  const pascal = parts
+    .map((p, i) =>
+      i === 0
+        ? p.toLowerCase()
+        : p.charAt(0).toUpperCase() + p.slice(1).toLowerCase(),
+    )
+    .join("")
+
+  const kebab = parts.map((p) => p.toLowerCase()).join("-")
+
+  return { pascal, kebab }
+}

